import { defineComponentStyle } from "@yamada-ui/react"
import {
  getInputPaddingEndResetStyle,
  getInputPaddingStartResetStyle,
  inputStyle,
} from "../input"

export const textareaStyle = defineComponentStyle({
  base: {
    ...inputStyle.base,
    resize: "vertical",
  },

  variants: {
    filled: inputStyle.variants?.filled,
    flushed: inputStyle.variants?.flushed,
    outline: inputStyle.variants?.outline,
    plain: inputStyle.variants?.plain,
  },

  sizes: {
    xs: {
      ...inputStyle.sizes?.xs,
      py: "{--space-y}",
    },
    sm: {
      ...inputStyle.sizes?.sm,
      py: "{--space-y}",
    },
    md: {
      ...inputStyle.sizes?.md,
      py: "{--space-y}",
    },
    lg: {
      ...inputStyle.sizes?.lg,
      py: "{--space-y}",
    },
    xl: {
      ...inputStyle.sizes?.xl,
      py: "{--space-y}",
    },
    "2xl": {
      ...inputStyle.sizes?.["2xl"],
      py: "{--space-y}",
    },
  },

  compounds: [
    {
      css: {
        ...getInputPaddingStartResetStyle(),
        ...getInputPaddingEndResetStyle(),
      },
      variant: "flushed",
      layer: "variant",
    },
  ],

  defaultProps: {
    size: "md",
    variant: "outline",
  },
})

export type TextareaStyle = typeof textareaStyle

import { a11y, page, render } from "#test/browser"
import { Textarea } from "./"

describe("<Textarea />", () => {
  test("renders component correctly", async () => {
    await a11y(<Textarea aria-label="Enter notes" defaultValue="hello" />)
  })

  test("sets `displayName` correctly", () => {
    expect(Textarea.displayName).toBe("Textarea")
  })

  test("sets `className` correctly", async () => {
    await render(<Textarea />)
    await expect.element(page.getByRole("textbox")).toHaveClass("ui-textarea")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Textarea />)
    expect(page.getByRole("textbox").element().tagName).toBe("TEXTAREA")
  })

  test("Disabled Textarea renders correctly", async () => {
    await render(<Textarea disabled />)
    await expect.element(page.getByRole("textbox")).toHaveAttribute("disabled")
  })

  test("Read-Only Textarea renders correctly", async () => {
    await render(<Textarea readOnly />)
    await expect
      .element(page.getByRole("textbox"))
      .toHaveAttribute("aria-readonly", "true")
  })

  test("Invalid Textarea renders correctly", async () => {
    await render(<Textarea invalid />)
    await expect
      .element(page.getByRole("textbox"))
      .toHaveAttribute("aria-invalid", "true")
  })

  test("Resize Textarea renders correctly", async () => {
    await render(<Textarea resize="none" />)
    await expect.element(page.getByRole("textbox")).toHaveStyle({
      resize: "none",
    })
  })

  test("Placeholder Textarea renders correctly", async () => {
    await render(<Textarea placeholder="text" />)
    await expect
      .element(page.getByRole("textbox"))
      .toHaveAttribute("placeholder", "text")
  })
  test("Rows Textarea renders correctly", async () => {
    await render(<Textarea rows={1} />)
    const textarea = page.getByRole("textbox").element() as HTMLTextAreaElement
    expect(textarea.rows).toBe(1)
  })

  test("Autosize Textarea renders correctly", async () => {
    let fontsData = "fonts" in document ? document.fonts : undefined

    Object.defineProperty(document, "fonts", {
      value: {
        addEventListener: vi.fn(),
        removeEventListener: vi.fn(),
      },
      writable: true,
    })
    await render(<Textarea autosize />)
    const textarea = page.getByRole("textbox").element() as HTMLTextAreaElement

    await expect.poll(() => textarea.rows).toBe(2)
    Object.defineProperty(document, "fonts", {
      value: fontsData,
      writable: true,
    })
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { FieldProps } from "../field"
import type { UseInputBorderProps } from "../input"
import type { TextareaStyle } from "./textarea.style"
import type { UseTextareaProps } from "./use-textarea"
import { createComponent } from "@yamada-ui/react"
import { useFieldProps } from "../field"
import { useInputBorder, useInputPropsContext } from "../input"
import { textareaStyle } from "./textarea.style"
import { useTextarea } from "./use-textarea"

export interface TextareaProps
  extends
    HTMLStyledProps<"textarea">,
    ThemeProps<TextareaStyle>,
    UseInputBorderProps,
    FieldProps,
    UseTextareaProps {}

const {
  PropsContext: TextareaPropsContext,
  usePropsContext: useTextareaPropsContext,
  withContext,
} = createComponent<TextareaProps, TextareaStyle>("textarea", textareaStyle)

export { TextareaPropsContext, useTextareaPropsContext }

/**
 * `Textarea` is a component used to obtain multi-line text input.
 *
 * @see https://yamada-ui.com/docs/components/textarea
 */
export const Textarea = withContext("textarea")(
  (props) => {
    const context = useInputPropsContext()

    return { rows: 2, ...context, ...props }
  },
  (props) => {
    const {
      props: { errorBorderColor, focusBorderColor, ...rest },
      ariaProps,
      dataProps,
      eventProps,
    } = useFieldProps(props)
    const { getTextareaProps } = useTextarea({
      ...ariaProps,
      ...dataProps,
      ...eventProps,
      ...rest,
    })
    const varProps = useInputBorder({ errorBorderColor, focusBorderColor })

    return {
      ...varProps,
      ...getTextareaProps(),
    }
  },
)

import type { UseAutosizeProps } from "./use-autosize"
import { page, render, renderHook } from "#test/browser"
import { useAutosize } from "./use-autosize"

const mockComputedStyle: Partial<CSSStyleDeclaration> = {
  borderBottomWidth: "1px",
  borderLeftWidth: "1px",
  borderRightWidth: "1px",
  borderTopWidth: "1px",
  boxSizing: "border-box",
  fontFamily: "sans-serif",
  fontSize: "16px",
  fontStyle: "normal",
  fontWeight: "400",
  letterSpacing: "normal",
  lineHeight: "20",
  paddingBottom: "8px",
  paddingLeft: "12px",
  paddingRight: "12px",
  paddingTop: "8px",
  tabSize: "8",
  textIndent: "0px",
  textRendering: "auto",
  textTransform: "none",
  width: "300px",
  wordBreak: "normal",
}

const setupComputedStyleMock = () => {
  const originalGetComputedStyle = window.getComputedStyle
  vi.spyOn(window, "getComputedStyle").mockImplementation(
    () => mockComputedStyle as CSSStyleDeclaration,
  )
  return () => {
    ;(window.getComputedStyle as any).mockRestore?.()
    window.getComputedStyle = originalGetComputedStyle
  }
}

const setupScrollHeightMock = (heightPerLine = 20) => {
  const originalCloneNode = HTMLElement.prototype.cloneNode
  HTMLElement.prototype.cloneNode = function (deep?: boolean) {
    const cloned = originalCloneNode.call(this, deep) as HTMLTextAreaElement
    Object.defineProperty(cloned, "scrollHeight", {
      get() {
        const lines = (this.value.match(/\n/g) || []).length + 1
        return lines * heightPerLine
      },
    })
    return cloned
  }
  return () => {
    HTMLElement.prototype.cloneNode = originalCloneNode
  }
}

const setupDocumentFontsMock = () => {
  const originalFonts = "fonts" in document ? document.fonts : undefined

  Object.defineProperty(document, "fonts", {
    configurable: true,
    value: {
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
    },
    writable: true,
  })

  return () => {
    Object.defineProperty(document, "fonts", {
      configurable: true,
      value: originalFonts,
      writable: true,
    })
  }
}

const AutoSizeTextarea = ({
  disabled,
  maxRows,
  minRows,
  placeholder,
  value,
}: UseAutosizeProps & { placeholder?: string; value?: string }) => {
  const { getTextareaProps } = useAutosize({
    disabled,
    maxRows,
    minRows,
  })

  return (
    <textarea
      data-testid="autosize-textarea"
      {...getTextareaProps({
        placeholder,
        readOnly: value != null || undefined,
        value,
      })}
    />
  )
}

const getTextarea = () =>
  page.getByTestId("autosize-textarea").element() as HTMLTextAreaElement

describe("useAutosize", () => {
  let cleanupComputedStyle: () => void
  let cleanupScrollHeight: () => void
  let cleanupFonts: () => void

  beforeEach(() => {
    cleanupComputedStyle = setupComputedStyleMock()
    cleanupScrollHeight = setupScrollHeightMock()
    cleanupFonts = setupDocumentFontsMock()
  })

  afterEach(() => {
    cleanupComputedStyle()
    cleanupScrollHeight()
    cleanupFonts()
    vi.restoreAllMocks()
  })

  test("adjusts the rows of the textarea based on content", async () => {
    const { user } = await render(<AutoSizeTextarea />)
    const textarea = getTextarea()

    await user.type(textarea, "Line 1\nLine 2\nLine 3\nLine 4\nLine 5")

    await expect.poll(() => textarea.rows).toBe(5)
  })

  test("does not exceed maxRows", async () => {
    const { user } = await render(<AutoSizeTextarea maxRows={3} />)
    const textarea = getTextarea()

    await user.type(textarea, "Line 1\nLine 2\nLine 3\nLine 4\nLine 5")

    await expect.poll(() => textarea.rows).toBe(3)
  })

  test("does not go below minRows", async () => {
    const { user } = await render(<AutoSizeTextarea minRows={4} />)
    const textarea = getTextarea()

    await user.type(textarea, "short")

    await expect.poll(() => textarea.rows).toBe(4)
  })

  test("uses placeholder when value is empty", async () => {
    await render(<AutoSizeTextarea placeholder="Enter text here" />)
    const textarea = getTextarea()

    await expect.poll(() => textarea.rows).toBe(2)
  })

  test("falls back to lineBreaks when scrollHeight is 0", async () => {
    cleanupScrollHeight()

    const originalCloneNode = HTMLElement.prototype.cloneNode
    HTMLElement.prototype.cloneNode = function (deep?: boolean) {
      const cloned = originalCloneNode.call(this, deep) as HTMLTextAreaElement
      Object.defineProperty(cloned, "scrollHeight", {
        get() {
          return 0
        },
      })
      return cloned
    }

    const { user } = await render(<AutoSizeTextarea maxRows={10} minRows={1} />)
    const textarea = getTextarea()

    await user.type(textarea, "Line 1\nLine 2\nLine 3")

    await expect.poll(() => textarea.rows).toBe(3)

    HTMLElement.prototype.cloneNode = originalCloneNode
  })

  test("sets resize to none when autosize is not disabled", async () => {
    await render(<AutoSizeTextarea />)

    expect(getTextarea().style.resize).toBe("none")
  })

  test("does not set resize when disabled", async () => {
    await render(<AutoSizeTextarea disabled />)

    expect(getTextarea().style.resize).toBe("")
  })

  test("does not resize when disabled", async () => {
    const { rerender } = await render(
      <AutoSizeTextarea disabled minRows={1} value="Line 1" />,
    )
    const textarea = getTextarea()

    await expect.poll(() => textarea.rows).toBe(2)

    await rerender(
      <AutoSizeTextarea
        disabled
        minRows={1}
        value={"Line 1\nLine 2\nLine 3\nLine 4\nLine 5"}
      />,
    )

    expect(textarea.rows).toBe(2)
  })

  test("resizes when value changes via rerender", async () => {
    const { rerender } = await render(
      <AutoSizeTextarea minRows={1} value="Line 1" />,
    )
    const textarea = getTextarea()

    await expect.poll(() => textarea.rows).toBe(1)

    await rerender(
      <AutoSizeTextarea minRows={1} value={"Line 1\nLine 2\nLine 3"} />,
    )

    await expect.poll(() => textarea.rows).toBe(3)
  })

  test("returns ref and onResizeTextarea from hook", async () => {
    const { result } = await renderHook(() => useAutosize())

    expect(result.current.ref).toBeDefined()
    expect(result.current.getTextareaProps).toBeDefined()
    expect(result.current.onResizeTextarea).toBeDefined()
  })

  test("skips resize when getSizingStyle returns null", async () => {
    cleanupComputedStyle()
    vi.spyOn(window, "getComputedStyle").mockImplementation(
      () => ({ boxSizing: "" }) as CSSStyleDeclaration,
    )

    const { user } = await render(<AutoSizeTextarea />)
    const textarea = getTextarea()

    await user.type(textarea, "Line 1\nLine 2\nLine 3")

    expect(textarea.rows).not.toBe(3)
  })

  test("does not resize when value has not changed", async () => {
    const appendChildSpy = vi.spyOn(document.body, "appendChild")
    const { rerender } = await render(
      <AutoSizeTextarea minRows={1} value="test" />,
    )
    const textarea = getTextarea()

    await expect.poll(() => textarea.rows).toBe(1)
    const appendCount = appendChildSpy.mock.calls.length

    await rerender(<AutoSizeTextarea minRows={1} value="test" />)

    expect(textarea.rows).toBe(1)
    expect(appendChildSpy).toHaveBeenCalledTimes(appendCount)
  })
})

"use client"

import type { PropGetter } from "@yamada-ui/react"
import { useCallback, useRef } from "react"
import {
  addDomEvent,
  createdDom,
  handlerAll,
  mergeRefs,
  noop,
  pickObject,
  useSafeLayoutEffect,
  useUpdateEffect,
} from "@yamada-ui/react"

const SIZING_STYLE_PROPERTIES = [
  "borderBottomWidth",
  "borderLeftWidth",
  "borderRightWidth",
  "borderTopWidth",
  "boxSizing",
  "fontFamily",
  "fontSize",
  "fontStyle",
  "fontWeight",
  "letterSpacing",
  "lineHeight",
  "paddingBottom",
  "paddingLeft",
  "paddingRight",
  "paddingTop",
  // non-standard
  "tabSize",
  "textIndent",
  // non-standard
  "textRendering",
  "textTransform",
  "width",
  "wordBreak",
] as const

const HIDDEN_STYLE = {
  height: "0",
  "max-height": "none",
  "min-height": "0",
  overflow: "hidden",
  position: "absolute",
  right: "0",
  top: "0",
  visibility: "hidden",
  "z-index": "-1000",
} as const

type SizingProperties = Extract<
  (typeof SIZING_STYLE_PROPERTIES)[number],
  keyof CSSStyleDeclaration
>

interface SizingStyle {
  border: number
  padding: number
  rowHeight: number
  style: Pick<CSSStyleDeclaration, SizingProperties>
}

const getSizingStyle = (el: HTMLElement): null | SizingStyle => {
  const style = window.getComputedStyle(el) as CSSStyleDeclaration | undefined

  if (style == null) return null

  const computedStyle = pickObject(style, SIZING_STYLE_PROPERTIES)

  if (computedStyle.boxSizing === "") return null

  const padding =
    parseFloat(computedStyle.paddingBottom) +
    parseFloat(computedStyle.paddingTop)

  const border =
    parseFloat(computedStyle.borderBottomWidth) +
    parseFloat(computedStyle.borderTopWidth)

  const rowHeight = parseFloat(computedStyle.lineHeight)

  return {
    style: computedStyle,
    border,
    padding,
    rowHeight,
  }
}

const setHiddenStyle = (el: HTMLElement) => {
  Object.keys(HIDDEN_STYLE).forEach((key) => {
    el.style.setProperty(
      key,
      HIDDEN_STYLE[key as keyof typeof HIDDEN_STYLE],
      "important",
    )
  })
}

const calcRows = (
  el: HTMLTextAreaElement,
  sizingStyle: SizingStyle,
  value: string,
  maxRows: number,
  minRows: number,
) => {
  const cloneEl = el.cloneNode() as HTMLTextAreaElement

  Object.assign(cloneEl.style, sizingStyle.style)

  setHiddenStyle(cloneEl)

  cloneEl.value = value

  document.body.appendChild(cloneEl)

  let rows: number

  if (cloneEl.scrollHeight) {
    const rowHeight = sizingStyle.rowHeight

    rows = Math.min(
      maxRows,
      Math.max(minRows, Math.floor(cloneEl.scrollHeight / rowHeight)),
    )
  } else {
    const lineBreaks = (value.match(/\n/g) || []).length

    rows = Math.min(maxRows, Math.max(minRows, lineBreaks + 1))
  }

  document.body.removeChild(cloneEl)

  return rows
}

export interface UseAutosizeProps {
  /**
   * If `true`, the Textarea height will not be adjusted.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * Autosize up to maxRows rows.
   *
   * @default Infinity
   */
  maxRows?: number
  /**
   * Autosize up to minRows rows.
   *
   * @default 2
   */
  minRows?: number
}

export const useAutosize = ({
  disabled = false,
  maxRows = Infinity,
  minRows = 2,
}: UseAutosizeProps = {}) => {
  const ref = useRef<HTMLTextAreaElement>(null)
  const beforeValueRef = useRef<string>(null)
  const value = ref.current?.value ?? ""

  const onResizeTextarea = useCallback(() => {
    const el = ref.current

    if (!el) return

    let { placeholder, value } = el

    if (value === beforeValueRef.current) return

    beforeValueRef.current = value

    value ||= placeholder || "x"

    const sizingStyle = getSizingStyle(el)

    if (!sizingStyle) return

    const rows = calcRows(el, sizingStyle, value, maxRows, minRows)

    el.rows = rows
  }, [ref, maxRows, minRows])

  const getTextareaProps: PropGetter<"textarea"> = useCallback(
    (props = {}) => ({
      ...props,
      ref: mergeRefs(props.ref, ref),
      style: { resize: !disabled ? "none" : undefined, ...props.style },
      onChange: handlerAll(props.onChange, !disabled ? onResizeTextarea : noop),
    }),
    [ref, onResizeTextarea, disabled],
  )

  useSafeLayoutEffect(() => {
    if (!createdDom() || disabled) return

    onResizeTextarea()

    const unsubscribeResize = addDomEvent(window, "resize", onResizeTextarea)
    const unsubscribeLoadingdone = addDomEvent(
      document.fonts,
      "loadingdone",
      onResizeTextarea,
    )

    return () => {
      unsubscribeResize()
      unsubscribeLoadingdone()
    }
  }, [])

  useUpdateEffect(() => {
    if (disabled) return

    onResizeTextarea()
  }, [value])

  return { ref, getTextareaProps, onResizeTextarea }
}

export type UseAutosizeReturn = ReturnType<typeof useAutosize>

"use client"

import type { ForwardedRef } from "react"
import type { HTMLProps, PropGetter } from "@yamada-ui/react"
import type { UseAutosizeProps } from "./use-autosize"
import { useCallback } from "react"
import { mergeProps, assignRef, mergeRefs } from "@yamada-ui/react"
import { useAutosize } from "./use-autosize"

export interface UseTextareaProps
  extends HTMLProps<"textarea">, Omit<UseAutosizeProps, "disabled" | "ref"> {
  /**
   * If `true`, the Textarea height auto-adjusts to text height.
   */
  autosize?: boolean
  /**
   * Ref to a resize function.
   */
  resizeRef?: ForwardedRef<() => void>
}

export const useTextarea = ({
  autosize,
  maxRows,
  minRows,
  resizeRef,
  ...rest
}: UseTextareaProps = {}) => {
  const { ref, onResizeTextarea } = useAutosize({
    disabled: !autosize,
    maxRows,
    minRows,
  })

  assignRef(resizeRef, onResizeTextarea)

  const getTextareaProps: PropGetter<"textarea"> = useCallback(
    (props = {}) => {
      const textareaProps = mergeProps(rest, props, {
        ref: mergeRefs(ref),
        ...(autosize
          ? {
              style: { resize: "none" as const },
              onChange: onResizeTextarea,
            }
          : {}),
      })()

      return textareaProps
    },
    [autosize, onResizeTextarea, rest, ref],
  )

  return {
    getTextareaProps,
    onResizeTextarea,
  }
}

export type UseTextareaReturn = ReturnType<typeof useTextarea>
